// ─────────────────────────────────────────────────────────────
//  src/utils/generateOfferLetter.js
//  Pixel-accurate replica of Royals Webtech Offer Letter PDF
//  Uses real logo + RWT watermark. Loads jsPDF from CDN.
// ─────────────────────────────────────────────────────────────

let _jsPDFPromise = null;
function loadJsPDF() {
  if (_jsPDFPromise) return _jsPDFPromise;
  _jsPDFPromise = new Promise((resolve, reject) => {
    if (window.jspdf?.jsPDF) { resolve(window.jspdf.jsPDF); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
    s.onload = () => window.jspdf?.jsPDF ? resolve(window.jspdf.jsPDF) : reject(new Error("jsPDF not found"));
    s.onerror = () => reject(new Error("Failed to load jsPDF"));
    document.head.appendChild(s);
  });
  return _jsPDFPromise;
}

// ── Embedded images (base64) ──────────────────────────────────
const LOGO_B64 = "data:image/png;base64,";
const WM_B64   = "data:image/png;base64,";

// ── Colours ───────────────────────────────────────────────────
const BLACK  = [0, 0, 0];
const DGRAY  = [50, 50, 50];
const MGRAY  = [100, 100, 100];
const BLUE_L = [0, 0, 180];      // hyperlink blue for email in header
const BORDER = [0, 0, 0];        // rule lines are black in real PDF

// ── Date helpers ──────────────────────────────────────────────
function ordinal(n) {
  const s = ["th","st","nd","rd"];
  const v = n % 100;
  return n + (s[(v-20)%10] || s[v] || s[0]);
}
function fmtDate(ds) {
  if (!ds) return "\u2014";
  const d = new Date(ds + "T00:00:00");
  return ordinal(d.getDate()) + " " + d.toLocaleString("en-IN",{month:"long"}) + " " + d.getFullYear();
}
function todayFmt() {
  const d = new Date();
  return ordinal(d.getDate()) + " " + d.toLocaleString("en-IN",{month:"long"}) + " " + d.getFullYear();
}
function formatId(id) {
  if (!id) return "";
  return id.replace(/-/g, "/");
}

// ── Draw watermark on current page ───────────────────────────
function drawWatermark(doc, pageW, pageH) {
  // Centre of page, large, very transparent (achieved by drawing lightly)
  // jsPDF doesn't support true opacity for images, so we draw at natural size, centred
  const wmW = 130, wmH = 100;
  const wmX = (pageW - wmW) / 2;
  const wmY = (pageH - wmH) / 2;
  doc.addImage(WM_B64, "PNG", wmX, wmY, wmW, wmH, undefined, "NONE", 0);
}

// ── Shared header ─────────────────────────────────────────────
// Returns the Y coordinate where body content should start
function drawHeader(doc, pageW) {
  // Logo — top left, ~55mm wide × ~10mm tall (matches real header proportions)
  const logoW = 62, logoH = 11.4;
  doc.addImage(LOGO_B64, "PNG", 14, 8, logoW, logoH);

  // Address block — top right, bold, small
  // "Office:" bold, rest normal
  const addrX = pageW - 14;
  let ay = 10;

  doc.setFont("times", "bold");
  doc.setFontSize(8.5);
  doc.setTextColor(...BLACK);
  doc.text("Office: ", addrX - doc.getTextWidth("Office: 4th Floor, JB Wing,"), ay, {align:"left"});

  // Full address right-aligned
  const addrLines = [
    { t: "Office: 4th Floor, JB Wing,",    bold: true  },
    { t: "Mangalwari Complex, Sadar,",      bold: false },
    { t: "Nagpur (MH) India Pin: 440001",   bold: false },
    { t: "hr@royalswebtechpvtltd.com",      bold: false, blue: true },
  ];
  addrLines.forEach(({ t, bold, blue }) => {
    doc.setFont("times", bold ? "bold" : "normal");
    doc.setFontSize(8.5);
    doc.setTextColor(...(blue ? BLUE_L : BLACK));
    doc.text(t, addrX, ay, { align: "right" });
    ay += 4;
  });

  // CIN line — left, below logo
  doc.setFont("times", "bold");
  doc.setFontSize(8.5);
  doc.setTextColor(...BLACK);
  doc.text("CIN. - U72900MH2018PTC313809", 14, 22);

  // Top horizontal rule (thick, black)
  doc.setDrawColor(...BORDER);
  doc.setLineWidth(0.6);
  doc.line(14, 25, pageW - 14, 25);

  // IT Services line — bold "IT Services Provider:" then normal text
  doc.setFont("times", "bold");
  doc.setFontSize(7.2);
  doc.setTextColor(...BLACK);
  const srvLabel = "IT Services Provider: ";
  doc.text(srvLabel, 14, 29);
  const srvLabelW = doc.getTextWidth(srvLabel);

  doc.setFont("times", "normal");
  doc.setFontSize(7.2);
  const srvText =
    "Website/Software Development Services, SEO, SMO, Digital Marketing Services, CIMS Software, Billing Software, MLM Software, School " +
    "Management Software, Hotel/Restaurant Management Software, Hospital Management Software, Medical Billing Software, ERP, Inventory Software";
  // First line: remaining width after label; continuation lines: full width
  const srvLine1W = pageW - 14 - srvLabelW - 14;
  const srvRestW  = pageW - 28;
  const srvLines1 = doc.splitTextToSize(srvText, srvLine1W);
  doc.text(srvLines1[0], 14 + srvLabelW, 29);
  if (srvLines1.length > 1) {
    // Re-wrap remainder at full width
    const remainder = srvLines1.slice(1).join(" ");
    const srvLines2 = doc.splitTextToSize(remainder, srvRestW);
    doc.text(srvLines2, 14, 33);
    var srvEndY = 29 + (1 + srvLines2.length - 1) * 4 + 4;
  } else {
    var srvEndY = 29 + 4;
  }

  // Bottom horizontal rule (thin)
  doc.setDrawColor(...BORDER);
  doc.setLineWidth(0.4);
  doc.line(14, srvEndY, pageW - 14, srvEndY);

  return srvEndY + 5; // body starts here
}

// ── Shared footer ─────────────────────────────────────────────
function drawFooter(doc, pageW, pageH) {
  // Layout (matches real PDF exactly):
  //   pageH - 20 : * disclaimer right-aligned (ABOVE top rule)
  //   pageH - 16 : top rule
  //   pageH - 10 : website + contact line (BETWEEN the two rules)
  //   pageH - 5  : bottom rule

  // "* These documents..." — right aligned, above the top rule
  doc.setFont("times", "normal");
  doc.setFontSize(7.5);
  doc.setTextColor(...MGRAY);
  doc.text("* These documents do not appear to be signed on to the MD", pageW - 14, pageH - 20, { align: "right" });

  // Top rule
  doc.setDrawColor(...BORDER);
  doc.setLineWidth(0.5);
  doc.line(14, pageH - 16, pageW - 14, pageH - 16);

  // Website + contact line — BETWEEN the two rules, centred
  doc.setFontSize(8);
  const line1 = "www.royalswebtechpvtltd.com";
  const line2 = "  Contact: +91 8788447944, E-mail: contact@royalswebtechpvtltd.com";
  doc.setFont("times", "bold");
  doc.setTextColor(...BLUE_L);
  const totalW = doc.getTextWidth(line1) + doc.getTextWidth(line2);
  let fx = (pageW - totalW) / 2;
  doc.text(line1, fx, pageH - 10);
  fx += doc.getTextWidth(line1);
  doc.setFont("times", "normal");
  doc.setTextColor(...BLACK);
  doc.text(line2, fx, pageH - 10);

  // Bottom rule
  doc.setDrawColor(...BORDER);
  doc.setLineWidth(0.5);
  doc.line(14, pageH - 5, pageW - 14, pageH - 5);
}

// ── PAGE 1 ────────────────────────────────────────────────────
function drawPage1(doc, { empId, name, role, joinDate, completionDate }, pageW, pageH) {
  drawWatermark(doc, pageW, pageH);
  const bodyStart = drawHeader(doc, pageW);
  let y = bodyStart + 2;

  // ── "OFFER LETTER" — centred, bold, underlined ──
  doc.setFont("times", "bold");
  doc.setFontSize(16);
  doc.setTextColor(...BLACK);
  const titleText = "OFFER LETTER";
  const titleW = doc.getTextWidth(titleText);
  const titleX = (pageW - titleW) / 2;
  doc.text(titleText, titleX, y);
  // Double underline (real PDF has underline + bold)
  doc.setDrawColor(...BLACK);
  doc.setLineWidth(0.5);
  doc.line(titleX, y + 1, titleX + titleW, y + 1);
  y += 10;

  // ── Ref + Date ──
  doc.setFont("times", "bold");
  doc.setFontSize(10);
  doc.setTextColor(...BLACK);
  doc.text("Ref: " + formatId(empId), 14, y);
  // Date with superscript "th" — done as small raised text
  const dateStr = "Date: " + todayFmt();
  doc.text(dateStr, pageW - 14, y, { align: "right" });
  y += 14;

  // ── Dear salutation ──
  doc.setFont("times", "bold");
  doc.setFontSize(11);
  doc.text("Dear " + name + ",", 14, y);
  y += 8;

  // ── Opening paragraph ──
  doc.setFont("times", "normal");
  doc.setFontSize(11);
  doc.setTextColor(...BLACK);

  // Render: "We are pleased to extend this [bold]Offer of Internship[/bold] with [bold]Royals Webtech Pvt. Ltd.[/bold] for the position of"
  // Then next line: bold role
  const line1Parts = [
    { t: "We are pleased to extend this ",    b: false },
    { t: "Offer of Internship",               b: true  },
    { t: " with ",                            b: false },
    { t: "Royals Webtech Pvt. Ltd.",          b: true  },
    { t: " for the position of",              b: false },
  ];
  let cx = 14;
  line1Parts.forEach(({ t, b }) => {
    doc.setFont("times", b ? "bold" : "normal");
    doc.text(t, cx, y);
    cx += doc.getTextWidth(t);
  });
  y += 5.5;
  doc.setFont("times", "bold");
  doc.text(role + ".", 14, y);
  y += 8;

  // Para 2
  doc.setFont("times", "normal");
  doc.setFontSize(11);
  const p2 = doc.splitTextToSize(
    "Following your application and interview, we are confident in your potential and are excited to have you join our team. The details of your internship are as follows:",
    pageW - 28
  );
  doc.text(p2, 14, y);
  y += p2.length * 5.5 + 5;

  // ── Internship Details heading ──
  doc.setFont("times", "bold");
  doc.setFontSize(11);
  doc.text("Internship Details", 14, y);
  y += 7;

  // ── Bullet details ──
  const endDisplay = completionDate ? fmtDate(completionDate) : "Till Project Completion";
  const details = [
    ["Position:",     role],
    ["Start Date:",   fmtDate(joinDate)],
    ["Duration:",     endDisplay],
    ["Reporting To:", "Assigned Manager (details will be shared upon joining)"],
    ["Work Location:","Royals Webtech Pvt. Ltd., 4th Floor, A Wing, Block No. 8, Mangalwari Complex, near Government Polytechnic, Sadar, Nagpur, Maharashtra 440001"],
  ];

  details.forEach(([label, value]) => {
    // Bullet character exactly like real PDF
    doc.setFont("times", "normal");
    doc.setFontSize(11);
    doc.setTextColor(...BLACK);
    doc.text("\u2022", 17, y);          // • character

    // Bold label
    doc.setFont("times", "bold");
    doc.text(label, 22, y);
    const labelW = doc.getTextWidth(label);

    // Normal value on same line
    doc.setFont("times", "normal");
    const valX   = 22 + labelW + 1;
    const valWid = pageW - valX - 14;
    const vLines = doc.splitTextToSize(value, valWid);
    doc.text(vLines, valX, y);
    // Continuation lines indented to match value start
    y += vLines.length * 5.5 + 2;
  });

  y += 5;

  // ── Acceptance ──
  doc.setFont("times", "normal");
  doc.setFontSize(11);
  const acc = doc.splitTextToSize(
    "Please confirm your acceptance of this offer by signing and submitting this document on or before your joining date.",
    pageW - 28
  );
  doc.text(acc, 14, y);
  y += acc.length * 5.5 + 7;

  // ── Welcome ──
  // Welcome line — inline bold on "Royals Webtech family"
  {
    doc.setFontSize(11);
    const wParts = [
      { t: "We welcome you to the ", b: false },
      { t: "Royals Webtech family",  b: true  },
      { t: " and look forward to your valuable contributions and learning journey with us.", b: false },
    ];
    let wx = 14;
    let wy = y;
    const wMaxW = pageW - 28;
    // Build full string to measure line breaks
    let full = wParts.map(p => p.t).join("");
    const wLines = doc.splitTextToSize(full, wMaxW);
    // Track char position across parts for bold
    let charPos = 0;
    let boldStart = wParts[0].t.length;
    let boldEnd   = boldStart + wParts[1].t.length;
    wLines.forEach((wline, li) => {
      let lx = 14;
      // Find bold ranges in this line
      let lineStart = charPos;
      let lineEnd   = charPos + wline.length;
      // Normal before bold
      const bS = Math.max(boldStart, lineStart);
      const bE = Math.min(boldEnd,   lineEnd);
      if (bS >= bE) {
        // All normal
        doc.setFont("times", "normal");
        doc.text(wline, lx, wy + li * 5.5);
      } else {
        // Split: normal | bold | normal
        const pre  = full.slice(lineStart, bS);
        const bold = full.slice(bS, bE);
        const post = full.slice(bE, lineEnd);
        doc.setFont("times", "normal");
        if (pre)  { doc.text(pre,  lx, wy + li * 5.5); lx += doc.getTextWidth(pre); }
        doc.setFont("times", "bold");
        if (bold) { doc.text(bold, lx, wy + li * 5.5); lx += doc.getTextWidth(bold); }
        doc.setFont("times", "normal");
        if (post) { doc.text(post, lx, wy + li * 5.5); }
      }
      charPos = lineEnd + 1; // +1 for space jsPDF adds
    });
    y += wLines.length * 5.5;
  }

  // ── Signature section (matches real PDF exactly) ──
  // "Date: _______________" with line
  const sigY = pageH - 56;
  doc.setFont("times", "bold");
  doc.setFontSize(11);
  doc.setTextColor(...BLACK);
  doc.text("Date:", 14, sigY);
  doc.setDrawColor(...BLACK);
  doc.setLineWidth(0.4);
  doc.line(27, sigY, 75, sigY);        // underline after "Date:"

  // Signature line
  doc.line(14, sigY + 14, 72, sigY + 14);

  // "Signature" label
  doc.setFont("times", "normal");
  doc.setFontSize(11);
  doc.text("Signature", 14, sigY + 19);

  // "Nagpur" centre
  doc.text("Nagpur", pageW / 2, sigY + 19, { align: "center" });

  // "HR Recruiter" right
  doc.setFont("times", "bold");
  doc.text("HR Recruiter", pageW - 14, sigY + 19, { align: "right" });

  // Second row labels
  doc.setFont("times", "bold");
  doc.text("Mr. " + name, 14, sigY + 25);

  doc.setFont("times", "bold");
  doc.text("Location", pageW / 2, sigY + 25, { align: "center" });

  doc.setFont("times", "normal");
  doc.text("Royals Webtech Pvt. Ltd.", pageW - 14, sigY + 25, { align: "right" });

  drawFooter(doc, pageW, pageH);
}

// ── Acknowledgement block ─────────────────────────────────────
function drawAck(doc, pageW, pageH, name) {
  const y = pageH - 52;
  doc.setFontSize(11);
  doc.setTextColor(...BLACK);

  // Build the full acknowledgement text
  const fullAck = "I, " + name + ", hereby acknowledge that I have read, understood, and agreed to the above-mentioned terms and conditions of internship with Royals Webtech Pvt. Ltd.";
  const ackLines = doc.splitTextToSize(fullAck, pageW - 28);

  // Render line by line with correct inline bold — no overlay trick
  let charCursor = 0;
  const boldRanges = [
    { start: "I, ".length, end: "I, ".length + name.length + 1 },           // "Name,"
    { start: fullAck.indexOf("Royals Webtech Pvt. Ltd."),
      end:   fullAck.indexOf("Royals Webtech Pvt. Ltd.") + "Royals Webtech Pvt. Ltd.".length },
  ];

  ackLines.forEach((line, li) => {
    const lineY   = y + li * 6;
    const lineEnd = charCursor + line.length;
    let lx = 14;

    let pos = charCursor;
    while (pos < lineEnd) {
      // Find next bold range that overlaps this line
      const bold = boldRanges.find(r => r.start < lineEnd && r.end > pos);
      if (bold && bold.start <= pos) {
        // We are inside a bold range
        const endInLine = Math.min(bold.end, lineEnd);
        const chunk = fullAck.slice(pos, endInLine);
        doc.setFont("times", "bold");
        doc.text(chunk, lx, lineY);
        lx += doc.getTextWidth(chunk);
        pos = endInLine;
      } else if (bold && bold.start > pos && bold.start < lineEnd) {
        // Normal text before the bold range
        const chunk = fullAck.slice(pos, bold.start);
        doc.setFont("times", "normal");
        doc.text(chunk, lx, lineY);
        lx += doc.getTextWidth(chunk);
        pos = bold.start;
      } else {
        // All normal till end of line
        const chunk = fullAck.slice(pos, lineEnd);
        doc.setFont("times", "normal");
        doc.text(chunk, lx, lineY);
        pos = lineEnd;
      }
    }
    charCursor = lineEnd + 1; // +1 for the space jsPDF strips between lines
  });

  // Gap between ack text and signature lines — matches real PDF spacing
  const sy = y + ackLines.length * 6 + 10;

  // "Signature:" label + underline
  doc.setFont("times", "bold");
  doc.setFontSize(11);
  doc.setTextColor(...BLACK);
  doc.text("Signature: ", 14, sy);
  doc.setDrawColor(...BLACK);
  doc.setLineWidth(0.4);
  doc.line(14 + doc.getTextWidth("Signature: "), sy, 90, sy);

  // "Date:" label + underline — extra gap below Signature line
  doc.text("Date: ", 14, sy + 9);
  doc.line(14 + doc.getTextWidth("Date: "), sy + 9, 90, sy + 9);
}

// ── Clause renderer ───────────────────────────────────────────
function renderClauses(doc, pageW, clauses, y) {
  clauses.forEach(([num, title, body, subs]) => {
    doc.setFont("times", "normal");
    doc.setFontSize(11);
    doc.setTextColor(...BLACK);
    doc.text(num + ".", 14, y);

    doc.setFont("times", "bold");
    doc.setFontSize(11);
    doc.text(title, 22, y);
    y += 5.5;

    if (body) {
      doc.setFont("times", "normal");
      doc.setFontSize(11);
      doc.setTextColor(...BLACK);
      const blines = doc.splitTextToSize(body, pageW - 36);
      doc.text(blines, 22, y);
      y += blines.length * 5.5;
    }

    if (subs) {
      subs.forEach(s => {
        doc.setFont("times", "normal");
        doc.setFontSize(11);
        doc.setTextColor(...BLACK);
        doc.text("o", 26, y);
        const sl = doc.splitTextToSize(s, pageW - 52);
        doc.text(sl, 32, y);
        y += sl.length * 5.5 + 1.5;
      });
    }

    y += 3;
  });
  return y;
}

// ── PAGE 2 ────────────────────────────────────────────────────
function drawPage2(doc, name, pageW, pageH) {
  drawWatermark(doc, pageW, pageH);
  const bodyStart = drawHeader(doc, pageW);
  let y = bodyStart + 2;

  // Title — bold, centred, NO underline in real PDF p2
  doc.setFont("times", "bold");
  doc.setFontSize(16);
  doc.setTextColor(...BLACK);
  const t = "TERMS & CONDITIONS FOR INTERNSHIP";
  doc.text(t, pageW / 2, y, { align: "center" });
  y += 9;

  // Intro — "...with [bold]Royals Webtech Pvt. Ltd.[/bold]:"
  doc.setFont("times", "normal");
  doc.setFontSize(11);
  const intro1 = "The following terms and conditions shall govern your internship with ";
  const intro2 = "Royals Webtech Pvt. Ltd.:";
  const introW1 = doc.getTextWidth(intro1);
  doc.text(intro1, 14, y);
  doc.setFont("times", "bold");
  doc.text(intro2, 14 + introW1, y);
  y += 7;

  // Clause 1 needs inline bold "15th December 2025"
  // Override clause 1 body render
  doc.setFont("times", "normal"); doc.setFontSize(11); doc.setTextColor(...BLACK);
  doc.text("1.", 14, y);
  doc.setFont("times", "bold");
  doc.text("Starting Date:", 22, y);
  doc.setFont("times", "normal");
  const sd1 = " The internship will be commencing from ";
  const sd1W = doc.getTextWidth("Starting Date:") + doc.getTextWidth(sd1);
  doc.text(sd1, 22 + doc.getTextWidth("Starting Date:"), y);
  doc.setFont("times", "bold");
  doc.text("15th December 2025", 22 + doc.getTextWidth("Starting Date:") + doc.getTextWidth(sd1), y);
  doc.setFont("times", "normal");
  doc.text(".", 22 + doc.getTextWidth("Starting Date:") + doc.getTextWidth(sd1) + doc.getTextWidth("15th December 2025"), y);
  y += 8;

  // Render clauses 2–7
  const clauses2to7 = [
    [2, "Attendance & Punctuality:", "Regular attendance is mandatory. Interns must report to work on time and maintain the discipline expected during office hours.", null],
    [3, "Office Timings:", "The official working hours are 10:30 AM to 6:30 PM (Monday to Friday). Interns are required to be punctual and adhere to the prescribed schedule.", null],
    [4, "Saturday Policy:", "Saturdays will be optional offline, depending on project requirements; otherwise, Saturdays will be treated as Work From Home (WFH). Interns must remain available and responsive during WFH hours.", null],
    [5, "Work Ethics:", "Interns are expected to maintain discipline, professionalism, and respect toward colleagues and company policies. Any act of misconduct may lead to termination.", null],
    [6, "Confidentiality & Non-Disclosure Agreement (NDA):", null, [
      "All information, code, data, and documents related to company or client operations are confidential.",
      "Interns must not disclose, share, or replicate any such information without authorization.",
      "The NDA obligation continues even after completion or termination of the internship.",
    ]],
    [7, "Intellectual Property Rights:", "Any work, idea, design, or code created during the internship remains the exclusive intellectual property of Royals Webtech Pvt. Ltd. Interns have no claim or ownership over such work.", null],
  ];
  y = renderClauses(doc, pageW, clauses2to7, y);

  drawAck(doc, pageW, pageH, name);
  drawFooter(doc, pageW, pageH);
}

// ── PAGE 3 ────────────────────────────────────────────────────
function drawPage3(doc, name, pageW, pageH) {
  drawWatermark(doc, pageW, pageH);
  const bodyStart = drawHeader(doc, pageW);
  let y = bodyStart + 2;

  const clauses3 = [
    [8,  "Leave Policy:", null, [
      "All leave requests must be made via email at least one day in advance to the reporting manager.",
      "Consecutive leave for more than two days without approval may result in disciplinary action or termination.",
      "Uninformed absence will be considered as leave without approval and may affect internship continuation.",
    ]],
    [9,  "Remote Work (WFH) Policy:", "WFH may be allowed under company discretion. Interns must remain active online during office hours and complete assigned tasks on time.", null],
    [10, "System & Asset Usage:", "If provided with company systems or credentials, interns must use them responsibly. Unauthorized access, sharing, or data tampering is strictly prohibited.", null],
    [11, "Performance Evaluation:", "Performance will be monitored based on learning attitude, consistency, code quality, teamwork, and professionalism.", null],
    [12, "Data Protection:", "All company and client data must be handled securely. Any data breach or negligence will result in immediate termination.", null],
    [13, "Conflicts of Interest:", "Interns must not engage in any external work or freelance projects that conflict with company interests during the internship period.", null],
    [14, "Termination Clause:", "The company reserves the right to terminate the internship without prior notice in case of policy violation, misconduct, or underperformance.", null],
    [15, "Completion Certificate:", "A certificate will be issued only upon successful completion of the internship and submission of assigned deliverables.", null],
    [16, "Legal Compliance:", "All disputes or legal matters shall be subject to the jurisdiction of Nagpur, Maharashtra.", null],
  ];

  y = renderClauses(doc, pageW, clauses3, y);

  drawAck(doc, pageW, pageH, name);
  drawFooter(doc, pageW, pageH);
}

// ── PUBLIC API ────────────────────────────────────────────────
export async function generateOfferLetter(employee) {
  const jsPDF = await loadJsPDF();
  const { empId, name, role, joinDate, completionDate } = employee;

  const doc   = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
  const pageW = doc.internal.pageSize.getWidth();
  const pageH = doc.internal.pageSize.getHeight();

  drawPage1(doc, { empId, name, role, joinDate, completionDate }, pageW, pageH);
  doc.addPage();
  drawPage2(doc, name, pageW, pageH);
  doc.addPage();
  drawPage3(doc, name, pageW, pageH);

  const safeName = (name || "Employee").trim().replace(/\s+/g, "_");
  const safeId   = formatId(empId || "").replace(/\//g, "_");
  doc.save("OfferLetter_" + safeName + "_" + safeId + ".pdf");
}